AP.BLOBS = BLOBS

local function Loaded(addonName)
    return C_AddOns and C_AddOns.IsAddOnLoaded and C_AddOns.IsAddOnLoaded(addonName) and true or false
end
AP.Loaded = Loaded

function AP.BlobEmpty(key)
    local s = BLOBS[key]
    return (not s) or s == ""
end

-- Each importer returns (ok:boolean, detail:string). On failure detail is a reason
-- ("empty" / "notloaded" / "decode" / a raw error). On success detail may be a UX hint
-- ("reload" -> the addon needs a /reload, "confirm" -> the addon shows its own dialog).

-- Details!  — DetailsAPI:ImportProfile(str, name) (boot.lua) forwards to Details:ImportProfile with
-- overwriteExisting=true: creates the named profile if missing, overwrites it if present, and switches
-- to it live (no reload). We call the lower-level method through pcall to capture its boolean return.
function AP.ImportDetails(blobKey, profileName)
    if AP.BlobEmpty(blobKey) then return false, "empty" end
    if not (Details and Details.ImportProfile) then return false, "notloaded" end
    local ok, ret = pcall(Details.ImportProfile, Details, BLOBS[blobKey], profileName, false, false, true)
    if not ok then return false, tostring(ret) end
    if ret == false then return false, "decode" end
    return true
end

-- Plater  — PlaterAPI:ImportProfile(str, key): creates/overwrites+switches. Assert-based (pcall).
-- The API deliberately skips ReloadUI, so recommend one.
function AP.ImportPlater(profileName)
    if AP.BlobEmpty("plater") then return false, "empty" end
    if not (PlaterAPI and PlaterAPI.ImportProfile) then return false, "notloaded" end
    local ok, err = pcall(PlaterAPI.ImportProfile, PlaterAPI, BLOBS.plater, profileName)
    if not ok then return false, tostring(err) end
    return true, "reload"
end

-- BuffReminders  — BuffReminders:Import(str, key): named profile, full refresh (no reload needed).
function AP.ImportBuffReminders(profileName)
    if AP.BlobEmpty("buffReminders") then return false, "empty" end
    if not (BuffReminders and BuffReminders.Import) then return false, "notloaded" end
    local ok, err = BuffReminders:Import(BLOBS.buffReminders, profileName)
    if not ok then return false, tostring(err) end
    return true
end

-- BliZzi_Interrupts  — BIT.Profiles:Import(name, str): a bundle string ignores the name and switches
-- to its embedded active profile; a single string is written to a slot named `name`. Live.
function AP.ImportBliZzi(profileName)
    if AP.BlobEmpty("blizzi") then return false, "empty" end
    local BIT = _G.BIT
    if not (BIT and BIT.Profiles and BIT.Profiles.Import) then return false, "notloaded" end
    local ok, msg = BIT.Profiles:Import(profileName, BLOBS.blizzi)
    if not ok then return false, tostring(msg) end
    return true
end

-- DandersFrames  — DandersFrames_Import(str, name) global: creates+switches, live refresh.
function AP.ImportDanders(profileName)
    if AP.BlobEmpty("dandersFrames") then return false, "empty" end
    if not _G.DandersFrames_Import then return false, "notloaded" end
    local ok, nameOrErr = _G.DandersFrames_Import(BLOBS.dandersFrames, profileName)
    if not ok then return false, tostring(nameOrErr) end
    return true
end

-- BigWigs CORE/plugin profile (BW2: string) — BigWigsAPI.RegisterProfile(addonName, str, name, cb):
-- auto-loads Core+Options, but ALWAYS shows BigWigs' own confirm popup (cannot be silent). It REJECTS a
-- per-boss (BWB1:) string, so boss options go through ImportBossOptions below.
function AP.ImportBigWigs(profileName)
    if AP.BlobEmpty("bigwigsCore") then return false, "empty" end
    if not (BigWigsAPI and BigWigsAPI.RegisterProfile) then return false, "notloaded" end
    local ok, err = pcall(BigWigsAPI.RegisterProfile, "UnbunkUtility", BLOBS.bigwigsCore, profileName)
    if not ok then return false, tostring(err) end
    return true, "confirm"
end

-- BigWigs PER-BOSS options (BWB1: string) — BigWigsAPI.ImportBossOptions(addonName, str, cb): applies the
-- boss-specific settings into the current profile (no name arg). Also shows BigWigs' own confirm popup and
-- may async-load boss zones. Feed it the BWB1: export; a BW2: profile string belongs to ImportBigWigs.
function AP.ImportBigWigsBoss()
    if AP.BlobEmpty("bigwigsBoss") then return false, "empty" end
    if not (BigWigsAPI and BigWigsAPI.ImportBossOptions) then return false, "notloaded" end
    local ok, err = pcall(BigWigsAPI.ImportBossOptions, "UnbunkUtility", BLOBS.bigwigsBoss)
    if not ok then return false, tostring(err) end
    return true, "confirm"
end

-- Method Raid Tools (MRT) — MRT_API:ImportProfile(str, key): creates/overwrites the named profile and
-- switches to it, silent, no reload (safe in combat). Format "MRTP…" (prefix kept, the API strips it).
-- NOTE this API path has no retail/classic version gate, so only feed it a Retail MRT export.
function AP.ImportMRT(profileName)
    if AP.BlobEmpty("mrt") then return false, "empty" end
    if not (MRT_API and MRT_API.ImportProfile) then return false, "notloaded" end
    local ok = MRT_API:ImportProfile(BLOBS.mrt, profileName)
    if not ok then return false, "decode" end
    return true
end

-- UnhaltedUnitFrames — its live importer (UUF:ImportSavedVariables) is a file-local private method that
-- is NOT reachable from outside. The only external entry point is the global UUFG:ImportUUF(str, key)
-- (Globals.lua:3 `UUFG = UUFG or {}`, Share.lua:168): it writes UUFDB.profiles[key] and db:SetProfile,
-- but does NOT refresh the frames, so a /reload is needed. On a bad string it prints "Invalid Import
-- String." and returns without erroring.
function AP.ImportUnhaltedUUF(profileKey)
    if AP.BlobEmpty("unhaltedUUF") then return false, "empty" end
    if not AP.Loaded("UnhaltedUnitFrames") then return false, "notloaded" end
    local G = _G.UUFG
    if not (G and G.ImportUUF) then return false, "notloaded" end
    local ok, err = pcall(G.ImportUUF, G, BLOBS.unhaltedUUF, profileKey)
    if not ok then return false, tostring(err) end
    return true, "reload"
end

-- Prat-3.0 — Prat:ImportProfile(str, key) on the GLOBAL Prat table writes Prat3DB.profiles[key] and
-- repoints this character's profileKey, but never calls db:SetProfile, so AceDB only applies it on a
-- /reload. It returns false only on a CBOR/Base64 decode failure and nil on success. NOTE the loaded
-- check is "Prat-3.0" (the folder), NOT "Prat" — that name is Prat's own legacy-2.0 detector.
function AP.ImportPrat(profileName)
    if AP.BlobEmpty("prat") then return false, "empty" end
    if not (Prat and Prat.ImportProfile) then return false, "notloaded" end
    local ok, ret = pcall(Prat.ImportProfile, Prat, BLOBS.prat, profileName)
    if not ok then return false, tostring(ret) end
    if ret == false then return false, "decode" end
    return true, "reload"
end

-- Prat has no in-game export button, and a huge base64 string is impractical to copy out of the chat
-- frame, so we capture the ACTIVE Prat profile here (Prat:ExportProfile of Prat.db's current profile) —
-- the exact C_EncodingUtil CBOR+Base64 string AP.ImportPrat consumes — for pasting into the prat blob.
function AP.ExportPrat()
    if not (Prat and Prat.ExportProfile and Prat.db and Prat.db.GetCurrentProfile) then return nil end
    local key = Prat.db:GetCurrentProfile()
    if not key then return nil end
    local ok, str = pcall(Prat.ExportProfile, Prat, key)
    if not ok or type(str) ~= "string" or str == "" then return nil end
    return str
end

-- Baganator — Baganator.API.ImportString(str, resultName) is a plain function (no self) that RAISES
-- error() on any invalid/mismatched string, so it MUST be pcall'd. It creates/overwrites the named
-- profile and switches to it live (ChangeProfile fires its refresh callbacks) — no /reload. overwrite is
-- hard-coded true, so a dedicated name like "Principal" avoids clobbering the user's own profiles.
function AP.ImportBaganator(profileName)
    if AP.BlobEmpty("baganator") then return false, "empty" end
    if not AP.Loaded("Baganator") then return false, "notloaded" end
    if not (Baganator and Baganator.API and Baganator.API.ImportString) then return false, "notloaded" end
    local ok, err = pcall(Baganator.API.ImportString, BLOBS.baganator, profileName)
    if not ok then return false, tostring(err) end
    return true
end

-- EnhanceQoL — EnhanceQoL.importProfile(str) is a plain global field: call it with a DOT and ONLY the
-- string (no self, no name). The imported profile takes the NAME embedded in the string (meta.profile),
-- so the profileName below is cosmetic. It writes EnhanceQoLDB + marks the profile active/global but does
-- not refresh live, so a /reload is needed. Returns false on a bad/foreign string.
function AP.ImportEnhanceQoL(profileName)
    if AP.BlobEmpty("enhanceQoL") then return false, "empty" end
    local EQOL = _G.EnhanceQoL
    if not (EQOL and EQOL.importProfile) then return false, "notloaded" end
    local ok, ret = pcall(EQOL.importProfile, BLOBS.enhanceQoL)
    if not ok then return false, tostring(ret) end
    if ret == false then return false, "decode" end
    return true, "reload"
end

-- ── Dominos (artificial round-trip) ──────────────────────────────────────────
-- Dominos has NO string export/import — its profiles are plain AceDB tables. So we roll our own,
-- using the SAME native pipeline as UnbunkUtility's own profile export: serialize the LIVE Dominos
-- profile into a "!UUDOM2!" blob (captured via the "Export current" button since Dominos can't emit one), and on
-- import inject it into a named Dominos profile IN PLACE (like ns.profiles ApplySnapshot) + switch.
-- A /reload then rebuilds Dominos' bars from the injected data.
-- Native 12.0 serialization (C_EncodingUtil: CBOR -> DEFLATE -> Base64), same pipeline as
-- ns.profiles Export. The sentinel bumped to "!UUDOM2!"; a baked "!UUDOM1!" blob (from the old
-- AceSerializer + LibDeflate path) no longer decodes — re-capture it via "Export current".
local C_EncodingUtil = C_EncodingUtil
local DEFLATE       = Enum and Enum.CompressionMethod and Enum.CompressionMethod.Deflate
local DOM_SENTINEL  = "!UUDOM2!"

local function DominosEncode(t)
    if not (C_EncodingUtil and DEFLATE) then return nil end
    local ok, out = pcall(function()
        return C_EncodingUtil.EncodeBase64(
            C_EncodingUtil.CompressString(C_EncodingUtil.SerializeCBOR(t), DEFLATE))
    end)
    if ok and type(out) == "string" then return DOM_SENTINEL .. out end
    return nil
end

local function DominosDecode(str)
    if type(str) ~= "string" or str:sub(1, #DOM_SENTINEL) ~= DOM_SENTINEL then return nil end
    if not (C_EncodingUtil and DEFLATE) then return nil end
    local body = (str:sub(#DOM_SENTINEL + 1)):gsub("%s", "")
    local ok1, dec = pcall(C_EncodingUtil.DecodeBase64, body); if not ok1 or type(dec) ~= "string" then return nil end
    local ok2, ser = pcall(C_EncodingUtil.DecompressString, dec, DEFLATE); if not ok2 or type(ser) ~= "string" then return nil end
    local ok3, res = pcall(C_EncodingUtil.DeserializeCBOR, ser); if not ok3 or type(res) ~= "table" then return nil end
    return res
end

-- Capture the CURRENT active Dominos profile into a paste-able string (for the `dominos` blob above).
function AP.ExportDominos()
    if not (Dominos and Dominos.db and Dominos.db.profile) then return nil end
    return DominosEncode(ns.DeepCopy(Dominos.db.profile))
end

-- Import the blob into a named Dominos profile (create/switch), overwriting its table in place.
-- Returns "reload": Dominos rebuilds its bars from the profile on load, so a /reload applies it cleanly.
function AP.ImportDominos(profileName)
    if AP.BlobEmpty("dominos") then return false, "empty" end
    if not (Dominos and Dominos.db and Dominos.db.SetProfile) then return false, "notloaded" end
    local snapshot = DominosDecode(BLOBS.dominos)
    if not snapshot then return false, "decode" end
    Dominos.db:SetProfile(profileName)     -- create + switch to "Principal"
    local p = Dominos.db.profile
    if type(p) == "table" then
        for k in pairs(p) do p[k] = nil end
        for k, v in pairs(snapshot) do p[k] = ns.DeepCopy(v) end
    end
    return true, "reload"
end

